package io.github.njw3995.fabricmmo.core.ui;
import io.github.njw3995.fabricmmo.api.NamespacedId;import java.util.Objects;import java.util.UUID;
public final class PlayerUiSettingsService { private final PlayerUiSettingsStore store; public PlayerUiSettingsService(PlayerUiSettingsStore store){this.store=Objects.requireNonNull(store,"store");} public PlayerUiSettings get(UUID id){return store.load(id);} public PlayerUiSettings setXpBar(UUID id,NamespacedId skill,XpBarMode mode){PlayerUiSettings s=get(id).withXpBar(skill,mode);store.save(id,s);return s;} public PlayerUiSettings resetXpBars(UUID id){PlayerUiSettings s=get(id).resetXpBars();store.save(id,s);return s;} public PlayerUiSettings setKeepScoreboard(UUID id,boolean keep){PlayerUiSettings s=get(id).withKeepScoreboard(keep);store.save(id,s);return s;} public void remove(UUID id){store.remove(id);} public void clear(){store.clear();} }
